import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    # Calculate utility of visiting each node taking into account time windows and avoidance of collective route congestion
    def calculate_utility(current_pos, customer, arrival_time, window_open, window_close):
        # Time window handling
        if arrival_time > window_close:
            time_penalty = (arrival_time - window_close) ** 2
        elif arrival_time < window_open:
            time_penalty = (window_open - arrival_time) ** 2
        else:
            time_penalty = -50  # Reward for hitting within the time window

        # Congestion prediction to avoid routes with high future truck density 
        congestion_penalty = 0
        for pos in all_truck_pos:
            if np.array_equal(pos, current_pos):
                continue
            if calculate_distance(pos, customer) < truck_speed * (window_close - current_time):
                congestion_penalty += 20  # Increasing penalty based on proximity of other trucks

        utility = -time_penalty - congestion_penalty
        return utility

    best_node = None
    max_utility = float('-inf')

    # Evaluate each unvisited customer in terms of utility
    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        utility = calculate_utility(cur_truck_pos, customer, arrival_time, window_open, window_close)

        if utility > max_utility:
            max_utility = utility
            best_node = i

    return best_node
